var e=[{id:`L7_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`바, 바즈라를 전부 튕겨냈어?`,JPN:`ヴァ、ヴァジュラを全部弾き飛ばした？`,ENG:`S-she deflected all of my vajra?`,TWN:`金，金剛杵都彈開咧？`},stage:{bg:`GAUNTLET`,slots:{L:null,C:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`으엑!`,JPN:`うげっ！`,ENG:`Geegh!`,TWN:`欸欸欸！`},stage:{bg:`GAUNTLET`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`SWORD_ADMIN_NULL_NULL`,text:{KOREA:`성가신 무기를 쓰긴 하지만, 정작 그걸 다루는 건 아직 서투르군.`,JPN:`厄介な武器を使ってはいるけれど、まだ上手に扱えないようね。`,ENG:`An annoying weapon you have there. But it seems you have not mastered it yet.`,TWN:`你使用的武器很厲害，但手法還不夠純熟。`},stage:{bg:`GAUNTLET`,slots:{L:null,C:{char_id:`SWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`노엘!!`,JPN:`ノエル！！`,ENG:`Noelle!!`,TWN:`洛艾兒！！`},stage:{bg:`GAUNTLET`,slots:{L:null,C:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`SWORD_ADMIN_NULL_NULL`,text:{KOREA:`안심해. 칼등으로 기절시켰을 뿐이야.`,JPN:`安心して。みね打ちで気絶させただけだから。`,ENG:`Rest assured. I have only knocked her out with the back side of the blade.`,TWN:`她沒事，我只有用刀背打暈她而已。`},stage:{bg:`GAUNTLET`,slots:{L:null,C:{char_id:`SWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`SWORD_ADMIN_NULL_NULL`,text:{KOREA:`하지만 반항한다면, 이 아이의 목숨은 없어.`,JPN:`だけど、抗うならこの子の命は保証できない。`,ENG:`Resist further, and the child will not live to see another day.`,TWN:`不過你要是敢反抗，她就會沒命。`},stage:{bg:`GAUNTLET`,slots:{L:null,C:{char_id:`SWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`GAUNTLET`,slots:{L:null,C:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`똑같아.`,JPN:`同じだわ。`,ENG:`It's the same.`,TWN:`又是這樣。`},stage:{bg:`GAUNTLET`,slots:{L:null,C:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`SWORD_ADMIN_NULL_NULL`,text:{KOREA:`뭐라고?`,JPN:`何だと？`,ENG:`What did you say?`,TWN:`你說什麼？`},stage:{bg:`GAUNTLET`,slots:{L:null,C:{char_id:`SWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L25_1`,type:`narration`,speaker:null,text:{KOREA:`그때와 똑같아.`,JPN:`あの時と同じ。`,ENG:`It's the same as that time.`,TWN:`和那時候一樣。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L28_1`,type:`dialog`,speaker:`CITIZEN_NPC_PROSECUTOR_NULL`,text:{KOREA:`<color=#ffd34c>루이즈 양, 여기는 신성한 법정입니다.</color>`,JPN:`<color=#ffd34c>ルイーズさん、ここは神聖なる法廷です。</color>`,ENG:`<color=#ffd34c>Miss Laurencin, you are under oath.</color>`,TWN:`<color=#ffd34c>露易絲，這裡是神聖的法庭。</color>`},stage:{bg:`CHARADE_001`,slots:{L:null,C:null,R:null}}},{id:`L29_1`,type:`dialog`,speaker:`CITIZEN_NPC_PROSECUTOR_NULL`,text:{KOREA:`<color=#ffd34c>거짓말하지 말고 솔직하게 말하면 돼요.</color>`,JPN:`<color=#ffd34c>嘘をつかず、正直に答えてください。</color>`,ENG:`<color=#ffd34c>All you have to do is speak the truth.</color>`,TWN:`<color=#ffd34c>不可以說謊，只要照實說就好。</color>`},stage:{bg:`CHARADE_001`,slots:{L:null,C:null,R:null}}},{id:`L30_1`,type:`narration`,speaker:null,text:{KOREA:`그 날 법정은 어둡고, 공기는 차가웠어.`,JPN:`あの日の法廷は暗くて、空気は冷たかったわ。`,ENG:`That day, the court room was dark and the air was cold.`,TWN:`那天法院裡很黑，空氣很冰冷。`},stage:{bg:`CHARADE_001`,slots:{L:null,C:null,R:null}}},{id:`L31_1`,type:`narration`,speaker:null,text:{KOREA:`보호소로 데리고 가는 임시 보호자의 손은 무척 딱딱했고.`,JPN:`私を保護所に連れていく臨時保護者の手はとても硬くて。`,ENG:`The hands of my temporary guardian felt stiff and cold as she took me to the orphanage.`,TWN:`帶我去育幼院的臨時監護人手很僵硬。`},stage:{bg:`CHARADE_001`,slots:{L:null,C:null,R:null}}}];export{e as default};